---
import { Font } from 'astro:assets';
import '../styles/global.css';
import SEO from '../components/SEO.astro';

interface Props {
  title: string;
  description?: string;
  image?: string;
  imageAlt?: string;
  type?: 'website' | 'article';
  articleMeta?: {
    publishedTime?: string; // ISO 8601
    modifiedTime?: string;  // ISO 8601
    author?: string;
    tags?: string[];
  };
}

const {
  title,
  description = 'A content-heavy static site built with Astro and Tailwind CSS',
  image,
  imageAlt,
  type = 'website',
  articleMeta,
} = Astro.props;
const canonicalURL = Astro.site ? new URL(Astro.url.pathname, Astro.site) : Astro.url;
const currentPath = Astro.url.pathname;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <title>{title}</title>
    <Font cssVariable="--font-inter" preload />
    <Font cssVariable="--font-mono" />
    <SEO
      title={title}
      description={description}
      canonicalURL={canonicalURL}
      image={image}
      imageAlt={imageAlt}
      type={type}
    />
    {type === 'article' && articleMeta?.publishedTime && (
      <meta property="article:published_time" content={articleMeta.publishedTime} />
    )}
    {type === 'article' && articleMeta?.modifiedTime && (
      <meta property="article:modified_time" content={articleMeta.modifiedTime} />
    )}
    {type === 'article' && articleMeta?.author && (
      <meta property="article:author" content={articleMeta.author} />
    )}
    {type === 'article' && articleMeta?.tags?.map(tag => (
      <meta property="article:tag" content={tag} />
    ))}
    <link rel="alternate" type="application/rss+xml" title="AstroStatic Blog RSS Feed" href="/rss.xml" />
    <slot name="head" />
  </head>
  <body class="min-h-screen bg-white text-gray-900 dark:bg-gray-950 dark:text-gray-100 antialiased">
    <a
      href="#main-content"
      class="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-50 focus:rounded focus:bg-white focus:px-4 focus:py-2 focus:text-sm focus:font-semibold focus:text-gray-900 focus:shadow-lg dark:focus:bg-gray-900 dark:focus:text-white"
    >
      Skip to main content
    </a>
    <nav aria-label="Main navigation" class="border-b border-gray-200 dark:border-gray-800" data-pagefind-ignore>
      <div class="mx-auto max-w-5xl px-4 py-4 flex items-center justify-between">
        <a href="/" class="text-xl font-bold tracking-tight rounded focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400">AstroStatic</a>
        <div class="flex gap-6 text-sm font-medium">
          <a
            href="/"
            aria-current={currentPath === '/' ? 'page' : undefined}
            class={`hover:text-blue-600 dark:hover:text-blue-400 transition-colors focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400 rounded ${currentPath === '/' ? 'text-blue-600 dark:text-blue-400 font-semibold' : ''}`}
          >Home</a>
          <a
            href="/blog"
            aria-current={currentPath === '/blog' || (currentPath.startsWith('/blog/') && !currentPath.startsWith('/blog/tags')) ? 'page' : undefined}
            class={`hover:text-blue-600 dark:hover:text-blue-400 transition-colors focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400 rounded ${currentPath === '/blog' || (currentPath.startsWith('/blog/') && !currentPath.startsWith('/blog/tags')) ? 'text-blue-600 dark:text-blue-400 font-semibold' : ''}`}
          >Blog</a>
          <a
            href="/blog/tags"
            aria-current={currentPath.startsWith('/blog/tags') ? 'page' : undefined}
            class={`hover:text-blue-600 dark:hover:text-blue-400 transition-colors focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400 rounded ${currentPath.startsWith('/blog/tags') ? 'text-blue-600 dark:text-blue-400 font-semibold' : ''}`}
          >Tags</a>
          <a
            href="/search"
            aria-current={currentPath === '/search' ? 'page' : undefined}
            class={`hover:text-blue-600 dark:hover:text-blue-400 transition-colors focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400 rounded ${currentPath === '/search' ? 'text-blue-600 dark:text-blue-400 font-semibold' : ''}`}
          >Search</a>
        </div>
      </div>
    </nav>

    <main id="main-content">
      <slot />
    </main>

    <footer class="border-t border-gray-200 dark:border-gray-800 mt-20" data-pagefind-ignore>
      <div class="mx-auto max-w-5xl px-4 py-8 text-center text-sm text-gray-500 dark:text-gray-400">
        <p>&copy; {new Date().getFullYear()} AstroStatic. Built with Astro &amp; Tailwind CSS.</p>
      </div>
    </footer>
  </body>
</html>

